SELECT n_name, EXTRACT(YEAR FROM o_orderdate) AS o_year, SUM(l_extendedprice * (1 - l_discount) - ps_supplycost * l_quantity) AS amount FROM customer, orders, lineitem, supplier, part, partsupp, nation WHERE c_custkey = o_custkey AND l_orderkey = o_orderkey AND l_suppkey = s_suppkey AND l_partkey = p_partkey AND ps_partkey = p_partkey AND ps_suppkey = s_suppkey AND c_nationkey = s_nationkey AND s_nationkey = n_nationkey AND p_name LIKE '%green%' GROUP BY n_name, EXTRACT(YEAR FROM o_orderdate) ORDER BY n_name, o_year DESC;